En Bash, `return` ne retourne qu'un **code de sortie entier** (0-255). Pour retourner une chaîne ou un nombre, utilisez `echo` avec substitution :

```bash
# Mauvaise approche (return avec entier)
carre() {
    return $(($1 * $1))   # limité à 0-255 !
}

# Bonne approche : echo + $()
carre() {
    local n=$1
    echo $((n * n))
}

resultat=$(carre 7)
echo "7² = $resultat"   # 7² = 49

# Retourner plusieurs valeurs (via stdout)
division() {
    local dividende=$1 diviseur=$2
    local quotient=$((dividende / diviseur))
    local reste=$((dividende % diviseur))
    echo "$quotient $reste"
}

lecture quotient reste <<< $(division 17 5)
echo "17 ÷ 5 = $quotient reste $reste"   # 17 ÷ 5 = 3 reste 2
```

